import sys

class Solution:
    def hasCycle(self, next: list[int]) -> bool:
        # Floyd's Tortoise and Hare algorithm on index list
        if not next:
            return False
        slow = 0
        fast = 0
        while True:
            # move slow one step
            if slow == -1:
                return False
            slow = next[slow]
            # move fast two steps
            if fast == -1:
                return False
            fast = next[fast]
            if fast == -1:
                return False
            fast = next[fast]
            if slow == -1 or fast == -1:
                return False
            if slow == fast:
                return True

