#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool hasCycle(vector<int>& next) {
        if (next.empty()) return false;
        int slow = 0, fast = 0;
        while (true) {
            if (slow == -1) return false;
            slow = next[slow];
            if (fast == -1) return false;
            fast = next[fast];
            if (fast == -1) return false;
            fast = next[fast];
            if (slow == -1 || fast == -1) return false;
            if (slow == fast) return true;
        }
        return false;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    // read node values (unused)
    for (int i = 0; i < n; ++i) {
        int val; cin >> val;
    }
    vector<int> nxt(n);
    for (int i = 0; i < n; ++i) {
        cin >> nxt[i];
    }
    Solution sol;
    bool ans = sol.hasCycle(nxt);
    cout << (ans ? "true" : "false") << "\n";
    return 0;
}
